INSERT INTO `settings` VALUES ('global','{\"hospital\":{\"name\":\"مستشفى الدكتور عبد القادر المتوكل النموذجي\",\"shortName\":\"مستشفى المتوكل\",\"logo\":\"data:image/bmp;base64,\",\"address\":\"شارع بغداد، صنعاء، الجمهورية اليمنية\",\"phone\":\"+967 01208080\",\"email\":\"info@almutawakel.com\",\"website\":\"www.almutawakel.com\",\"description\":\"مستشفى متخصص يقدم خدمات طبية متميزة بأعلى معايير الجودة\",\"workingHours\":\"24 ساعة / 7 أيام\",\"operatingTitle\":\"خير من يعتني واكثر من يهتم\",\"welcomeMessage\":\"اهلا بك في مستشفى الدكتور عبدالقادر المتوكل النموذجي, نسعد بمشاركة رأيك\"},\"departments\":[{\"id\":\"dept-1\",\"name\":\"الطوارئ\",\"isActive\":true,\"color\":\"#EF4444\"},{\"id\":\"dept-2\",\"name\":\"العيادات الخارجية\",\"isActive\":true,\"color\":\"#3B82F6\"},{\"id\":\"dept-3\",\"name\":\"الباطنية\",\"isActive\":true,\"color\":\"#10B981\"},{\"id\":\"dept-4\",\"name\":\"الجراحة\",\"isActive\":true,\"color\":\"#8B5CF6\"},{\"id\":\"dept-5\",\"name\":\"الأطفال\",\"isActive\":true,\"color\":\"#F59E0B\"},{\"id\":\"dept-6\",\"name\":\"النساء والولادة\",\"isActive\":true,\"color\":\"#EC4899\"},{\"id\":\"dept-7\",\"name\":\"العظام\",\"isActive\":true,\"color\":\"#6366F1\"},{\"id\":\"dept-8\",\"name\":\"العيون\",\"isActive\":true,\"color\":\"#14B8A6\"},{\"id\":\"dept-9\",\"name\":\"الأنف والأذن والحنجرة\",\"isActive\":true,\"color\":\"#F97316\"},{\"id\":\"dept-10\",\"name\":\"الأسنان\",\"isActive\":true,\"color\":\"#06B6D4\"},{\"id\":\"dept-11\",\"name\":\"القلب\",\"isActive\":true,\"color\":\"#DC2626\"},{\"id\":\"dept-12\",\"name\":\"المختبر والأشعة\",\"isActive\":true,\"color\":\"#7C3AED\"}],\"ageGroups\":[{\"id\":\"age-1\",\"label\":\"أقل من 18 سنة\"},{\"id\":\"age-2\",\"label\":\"18 - 30 سنة\"},{\"id\":\"age-3\",\"label\":\"31 - 45 سنة\"},{\"id\":\"age-4\",\"label\":\"46 - 60 سنة\"},{\"id\":\"age-5\",\"label\":\"أكثر من 60 سنة\"}],\"visitTypes\":[{\"id\":\"vt-1\",\"label\":\"زيارة طارئة\"},{\"id\":\"vt-2\",\"label\":\"موعد مسبق\"},{\"id\":\"vt-3\",\"label\":\"تنويم\"},{\"id\":\"vt-4\",\"label\":\"مراجعة\"},{\"id\":\"vt-5\",\"label\":\"عملية جراحية\"}],\"surveySettings\":{\"allowAnonymous\":true,\"requireAllQuestions\":false,\"requireName\":false,\"requirePhone\":false,\"showProgressBar\":true,\"enableThankYouPage\":true,\"thankYouMessage\":\"شكراً لمشاركتكم! رأيكم يساعدنا في تحسين خدماتنا.\"},\"appearance\":{\"primaryColor\":\"#0d9488\",\"secondaryColor\":\"#10b981\",\"fontFamily\":\"Cairo\"},\"activatedPredictivePlans\":[]}',NULL);
