  `ageGroup` varchar(191) DEFAULT NULL,
  `gender` varchar(191) DEFAULT NULL,
  `visitType` varchar(191) DEFAULT NULL,
  `department` varchar(191) NOT NULL,
  `overallScore` int(11) NOT NULL,
  `submittedAt` datetime(3) NOT NULL DEFAULT current_timestamp(3),
  `tenantId` varchar(191) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `survey_responses_department_idx` (`department`),
  KEY `survey_responses_submittedAt_idx` (`submittedAt`),
