  KEY `survey_responses_patientPhone_idx` (`patientPhone`),
  KEY `survey_responses_overallScore_idx` (`overallScore`),
  KEY `survey_responses_department_submittedAt_idx` (`department`,`submittedAt`),
  KEY `survey_responses_surveyId_idx` (`surveyId`),
  KEY `survey_responses_tenantId_idx` (`tenantId`),
  CONSTRAINT `survey_responses_surveyId_fkey` FOREIGN KEY (`surveyId`) REFERENCES `surveys` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `survey_responses_tenantId_fkey` FOREIGN KEY (`tenantId`) REFERENCES `tenants` (`id`) ON DELETE SET NULL ON UPDATE CASCADE
